那么Waker的话，我大概理解大神的解释。
有一点疑问，设置非阻塞可以理解，但是为什么要设置FD_CLOEXEC呢，据我所知，这个用在fork子进程然后有exec操作的时候会自动关闭子进程的fd（虽然不知道为何非要关闭，感觉父进程去关闭fd就好了呀，难不成还有类似python的GC的引用-1，如果没减少到0就无法回收？还是socket端口占用？），但是这里又不会fork。。为啥非要搞这个FD_CLOEXEC（close-on-exec）?
```
def set_close_exec(fd):
    flags = fcntl.fcntl(fd, fcntl.F_GETFD)
    fcntl.fcntl(fd, fcntl.F_SETFD, flags | fcntl.FD_CLOEXEC)


def _set_nonblocking(fd):
    flags = fcntl.fcntl(fd, fcntl.F_GETFL)
    fcntl.fcntl(fd, fcntl.F_SETFL, flags | os.O_NONBLOCK)


class Waker(interface.Waker):
    def __init__(self):
        r, w = os.pipe()
        _set_nonblocking(r)
        _set_nonblocking(w)
        set_close_exec(r)
        set_close_exec(w)
        self.reader = os.fdopen(r, "rb", 0)
        self.writer = os.fdopen(w, "wb", 0)

    def fileno(self):
        return self.reader.fileno()

    def write_fileno(self):
        return self.writer.fileno()

    def wake(self):
        try:
            self.writer.write(b"x")
        except IOError:
            pass

    def consume(self):
        try:
            while True:
                result = self.reader.read()
                if not result:
                    break
        except IOError:
            pass

    def close(self):
        self.reader.close()
        self.writer.close()
```

